1	/**
2	 * Voice allocator: 16-voice fixed pool with oldest-steal + 5ms crossfade.
3	 * INV-5: Fixed pool size, never grows.
4	 * MIT-H4-5: Oldest-steal with 5ms crossfade on stolen voices.
5	 * R-STA-05: Legato mode with pitch glide.
6	 *
7	 * Zero-allocation in allocate/release — no objects created at runtime.
8	 */
9	
10	/** Maximum number of concurrent voices */
11	export const MAX_VOICES = 16;
12	
13	/** Crossfade time in seconds when stealing a voice (MIT-H4-5) */
14	export const STEAL_CROSSFADE_S = 0.005;
15	
16	export type VoiceState = "idle" | "active" | "releasing" | "stealing";
17	
18	export type Voice = {
19	  state: VoiceState;
20	  note: number; // MIDI note number (current or old during steal)
21	  velocity: number; // 0..127
22	  /** Monotonically increasing counter set on each note-on for oldest-steal */
23	  age: number;
24	  /** Samples elapsed in steal crossfade */
25	  stealFadeSamples: number;
26	  /** Crossfade gain for old voice being stolen (1 -> 0 over 5ms) */
27	  stealFadeGain: number;
28	  /** Pending note to apply after steal crossfade completes */
29	  pendingNote: number;
30	  /** Pending velocity to apply after steal crossfade completes */
31	  pendingVelocity: number;
32	};
33	
34	export type StealResult = {
35	  readonly data: readonly number[];
36	  readonly count: number;
37	};
38	
39	export type VoiceAllocator = {
40	  readonly voices: readonly Voice[];
41	  noteOn(note: number, velocity: number, legato: boolean): number;
42	  noteOff(note: number): number;
43	  /** Advance steal crossfades. Returns {data, count} — iterate data[0..count). */
44	  processStealFade(sampleRate: number): StealResult;
45	  markIdle(index: number): void;
46	  reset(): void;
47	};
48	
49	/** Safe array access (pool is fixed-size). */
50	function v(voices: Voice[], i: number): Voice {
51	  const voice = voices[i];
52	  if (!voice) throw new Error("Voice index out of bounds");
53	  return voice;
54	}
55	
56	export function createVoiceAllocator(): VoiceAllocator {
57	  let ageCounter = 0;
58	
59	  // Pre-allocated fixed-size array + result object for zero-allocation processStealFade
60	  const completedSteals: number[] = new Array<number>(MAX_VOICES).fill(0);
61	  let completedCount = 0;
62	  const stealResult: { readonly data: readonly number[]; count: number } = {
63	    data: completedSteals,
64	    count: 0,
65	  };
66	
67	  // Cached crossfade length (computed on first processStealFade call)
68	  let cachedCrossfadeSamples = 0;
69	
70	  const voices: Voice[] = Array.from({ length: MAX_VOICES }, () => ({
71	    state: "idle" as VoiceState,
72	    note: -1,
73	    velocity: 0,
74	    age: 0,
75	    stealFadeSamples: 0,
76	    stealFadeGain: 0,
77	    pendingNote: -1,
78	    pendingVelocity: 0,
79	  }));
80	
81	  function findIdleVoice(): number {
82	    for (let i = 0; i < MAX_VOICES; i++) {
83	      if (v(voices, i).state === "idle") return i;
84	    }
85	    return -1;
86	  }
87	
88	  function findOldestActive(): number {
89	    let oldestIdx = -1;
90	    let oldestAge = Infinity;
91	
92	    // Prefer stealing releasing voices first
93	    for (let i = 0; i < MAX_VOICES; i++) {
94	      const voice = v(voices, i);
95	      if (voice.state === "releasing" && voice.age < oldestAge) {
96	        oldestAge = voice.age;
97	        oldestIdx = i;
98	      }
99	    }
100	
101	    if (oldestIdx === -1) {
102	      for (let i = 0; i < MAX_VOICES; i++) {
103	        const voice = v(voices, i);
104	        if (
105	          (voice.state === "active" || voice.state === "stealing") &&
106	          voice.age < oldestAge
107	        ) {
108	          oldestAge = voice.age;
109	          oldestIdx = i;
110	        }
111	      }
112	    }
113	
114	    return oldestIdx;
115	  }
116	
117	  function findVoiceForNote(note: number): number {
118	    for (let i = 0; i < MAX_VOICES; i++) {
119	      const voice = v(voices, i);
120	      if (
121	        voice.note === note &&
122	        (voice.state === "active" || voice.state === "releasing")
123	      ) {
124	        return i;
125	      }
126	    }
127	    return -1;
128	  }
129	
130	  const allocator: VoiceAllocator = {
131	    voices,
132	
133	    noteOn(note: number, velocity: number, legato: boolean): number {
134	      ageCounter++;
135	
136	      if (legato) {
137	        const existing = findVoiceForNote(note);
138	        if (existing !== -1) {
139	          const voice = v(voices, existing);
140	          voice.note = note;
141	          voice.velocity = velocity;
142	          voice.age = ageCounter;
143	          voice.state = "active";
144	          return existing;
145	        }
146	        // Find most recently played active voice (highest age)
147	        let bestIdx = -1;
148	        let bestAge = -1;
149	        for (let i = 0; i < MAX_VOICES; i++) {
150	          const voice = v(voices, i);
151	          if (voice.state === "active" && voice.age > bestAge) {
152	            bestAge = voice.age;
153	            bestIdx = i;
154	          }
155	        }
156	        if (bestIdx !== -1) {
157	          const voice = v(voices, bestIdx);
158	          voice.note = note;
159	          voice.velocity = velocity;
160	          voice.age = ageCounter;
161	          return bestIdx;
162	        }
163	      }
164	
165	      let idx = findIdleVoice();
166	
167	      if (idx === -1) {
168	        // All voices busy — steal oldest (MIT-H4-5)
169	        idx = findOldestActive();
170	        if (idx !== -1) {
171	          const voice = v(voices, idx);
172	          // Keep old note rendering during crossfade
173	          voice.state = "stealing";
174	          voice.stealFadeSamples = 0;
175	          voice.stealFadeGain = 1;
176	          voice.pendingNote = note;
177	          voice.pendingVelocity = velocity;
178	          voice.age = ageCounter;
179	          // DON'T overwrite note/velocity — old voice continues rendering
180	          return idx;
181	        }
182	      }
183	
184	      if (idx === -1) {
185	        idx = 0;
186	      }
187	
188	      const voice = v(voices, idx);
189	      voice.note = note;
190	      voice.velocity = velocity;
191	      voice.age = ageCounter;
192	      voice.state = "active";
193	      voice.stealFadeSamples = 0;
194	      voice.stealFadeGain = 0;
195	      voice.pendingNote = -1;
196	      voice.pendingVelocity = 0;
197	
198	      return idx;
199	    },
200	
201	    noteOff(note: number): number {
202	      const idx = findVoiceForNote(note);
203	      if (idx === -1) return -1;
204	
205	      v(voices, idx).state = "releasing";
206	      return idx;
207	    },
208	
209	    processStealFade(sampleRate: number): StealResult {
210	      if (cachedCrossfadeSamples === 0) {
211	        cachedCrossfadeSamples = Math.floor(STEAL_CROSSFADE_S * sampleRate);
212	      }
213	      completedCount = 0;
214	
215	      for (let i = 0; i < MAX_VOICES; i++) {
216	        const voice = v(voices, i);
217	        if (voice.state === "stealing") {
218	          voice.stealFadeSamples++;
219	          voice.stealFadeGain = Math.max(
220	            0,
221	            1 - voice.stealFadeSamples / cachedCrossfadeSamples,
222	          );
223	          if (voice.stealFadeSamples >= cachedCrossfadeSamples) {
224	            // Crossfade complete — apply pending note
225	            voice.note = voice.pendingNote;
226	            voice.velocity = voice.pendingVelocity;
227	            voice.state = "active";
228	            voice.stealFadeGain = 0;
229	            voice.stealFadeSamples = 0;
230	            voice.pendingNote = -1;
231	            voice.pendingVelocity = 0;
232	            completedSteals[completedCount++] = i;
233	          }
234	        }
235	      }
236	
237	      stealResult.count = completedCount;
238	      return stealResult;
239	    },
240	
241	    markIdle(index: number): void {
242	      if (index >= 0 && index < MAX_VOICES) {
243	        const voice = v(voices, index);
244	        voice.state = "idle";
245	        voice.note = -1;
246	        voice.velocity = 0;
247	        voice.stealFadeSamples = 0;
248	        voice.stealFadeGain = 0;
249	        voice.pendingNote = -1;
250	        voice.pendingVelocity = 0;
251	      }
252	    },
253	
254	    reset(): void {
255	      ageCounter = 0;
256	      for (let i = 0; i < MAX_VOICES; i++) {
257	        const voice = v(voices, i);
258	        voice.state = "idle";
259	        voice.note = -1;
260	        voice.velocity = 0;
261	        voice.age = 0;
262	        voice.stealFadeSamples = 0;
263	        voice.stealFadeGain = 0;
264	        voice.pendingNote = -1;
265	        voice.pendingVelocity = 0;
266	      }
267	    },
268	  };
269	
270	  return allocator;
271	}
272

1	/**
2	 * Core types for the track system.
3	 * Tracks contain clips; clips are non-destructive references to audio sources
4	 * or containers for MIDI note events.
5	 */
6	
7	export type TrackType = "audio" | "instrument";
8	
9	export type MIDINoteEvent = {
10	  readonly id: string;
11	  readonly pitch: number; // 0-127
12	  readonly velocity: number; // 0-127
13	  readonly startTime: number; // seconds, relative to clip start
14	  readonly duration: number; // seconds
15	};
16	
17	export type AudioClipModel = {
18	  readonly type: "audio";
19	  readonly id: string;
20	  readonly trackId: string;
21	  readonly sourceId: string;
22	  readonly startTime: number; // seconds on timeline
23	  readonly sourceOffset: number; // seconds into source
24	  readonly duration: number; // seconds
25	  readonly gain: number; // 0..2
26	  readonly fadeIn: number; // seconds
27	  readonly fadeOut: number; // seconds
28	  readonly name: string;
29	};
30	
31	export type MidiClipModel = {
32	  readonly type: "midi";
33	  readonly id: string;
34	  readonly trackId: string;
35	  readonly startTime: number; // seconds on timeline
36	  readonly duration: number; // seconds
37	  readonly noteEvents: readonly MIDINoteEvent[];
38	  readonly name: string;
39	};
40	
41	export type ClipModel = AudioClipModel | MidiClipModel;
42	
43	export function isAudioClip(clip: ClipModel): clip is AudioClipModel {
44	  return clip.type === "audio";
45	}
46	
47	export function isMidiClip(clip: ClipModel): clip is MidiClipModel {
48	  return clip.type === "midi";
49	}
50	
51	export type TrackModel = {
52	  readonly id: string;
53	  readonly name: string;
54	  readonly type: TrackType;
55	  readonly color: string;
56	  readonly muted: boolean;
57	  readonly solo: boolean;
58	  readonly armed: boolean;
59	  readonly soloIsolate: boolean;
60	  readonly volume: number; // 0..2
61	  readonly pan: number; // -1..1
62	  readonly clipIds: readonly string[];
63	};
