1	/**
2	 * Modulation engine: pure, zero-allocation functions for computing
3	 * modulation offsets from routes. Used inside the AudioWorklet processor.
4	 *
5	 * Design: Pre-allocated accumulators are reset each quantum, then
6	 * each active route adds source * amount to its destination accumulator.
7	 * The processor reads accumulators to offset synth parameters.
8	 */
9	
10	// ─── Source and destination index maps (numeric for worklet) ───
11	
12	export const SOURCE_INDEX = {
13	  lfo1: 0,
14	  lfo2: 1,
15	  ampEnv: 2,
16	  filterEnv: 3,
17	  velocity: 4,
18	  aftertouch: 5,
19	  modWheel: 6,
20	  pitchBend: 7,
21	} as const;
22	
23	export const DEST_INDEX = {
24	  osc1Pitch: 0,
25	  osc2Pitch: 1,
26	  oscMix: 2,
27	  filterCutoff: 3,
28	  filterResonance: 4,
29	  ampLevel: 5,
30	  lfo1Rate: 6,
31	  lfo2Rate: 7,
32	} as const;
33	
34	// ─── Accumulators ───
35	
36	export type ModAccumulators = {
37	  osc1Pitch: number;
38	  osc2Pitch: number;
39	  oscMix: number;
40	  filterCutoff: number;
41	  filterResonance: number;
42	  ampLevel: number;
43	  lfo1Rate: number;
44	  lfo2Rate: number;
45	};
46	
47	export function createModAccumulators(): ModAccumulators {
48	  return {
49	    osc1Pitch: 0,
50	    osc2Pitch: 0,
51	    oscMix: 0,
52	    filterCutoff: 0,
53	    filterResonance: 0,
54	    ampLevel: 0,
55	    lfo1Rate: 0,
56	    lfo2Rate: 0,
57	  };
58	}
59	
60	export function resetAccumulators(acc: ModAccumulators): void {
61	  acc.osc1Pitch = 0;
62	  acc.osc2Pitch = 0;
63	  acc.oscMix = 0;
64	  acc.filterCutoff = 0;
65	  acc.filterResonance = 0;
66	  acc.ampLevel = 0;
67	  acc.lfo1Rate = 0;
68	  acc.lfo2Rate = 0;
69	}
70	
71	// Dest keys indexed by DEST_INDEX values for fast lookup
72	const DEST_KEYS: readonly (keyof ModAccumulators)[] = [
73	  "osc1Pitch",
74	  "osc2Pitch",
75	  "oscMix",
76	  "filterCutoff",
77	  "filterResonance",
78	  "ampLevel",
79	  "lfo1Rate",
80	  "lfo2Rate",
81	];
82	
83	/**
84	 * Apply a single modulation route to accumulators.
85	 * Zero-allocation: reads from pre-allocated sourceValues array,
86	 * writes to pre-allocated accumulators object.
87	 */
88	export function applyModRoute(
89	  acc: ModAccumulators,
90	  sourceValues: Float64Array,
91	  sourceIdx: number,
92	  destIdx: number,
93	  amount: number,
94	  bipolar: boolean,
95	): void {
96	  const raw = sourceValues[sourceIdx] ?? 0;
97	  const value = bipolar ? raw : (raw + 1) / 2;
98	  const key = DEST_KEYS[destIdx];
99	  if (key !== undefined) {
100	    acc[key] += value * amount;
101	  }
102	}
103	
104	// ─── Serialized route format for worklet MessagePort ───
105	
106	export type WorkletModRoute = {
107	  sourceIdx: number;
108	  destIdx: number;
109	  amount: number;
110	  bipolar: boolean;
111	};
