export const DEFAULT_INSTRUMENT_PARAMS: Record<
  DrumInstrumentId,
  DrumInstrumentParams
> = {
  bd: { tone: 1000, decay: 0.5, tune: 1.0, volume: 0.9 },
  sd: { tone: 5000, decay: 0.3, tune: 1.0, volume: 0.8 },
  lt: { tone: 800, decay: 0.4, tune: 0.8, volume: 0.7 },
