  /** Set a modulation source value (aftertouch, modWheel, pitchBend). */
  setModSource(source: string, value: number): void;
  /** Connect to a mixer channel. */
  connectToMixer(mixer: MixerEngine, trackId: string): void;
  /** Disconnect from mixer. */
  disconnectFromMixer(mixer: MixerEngine, trackId: string): void;
  /** Clean up all resources. */
  dispose(): void;
};

/** URL for the worklet processor module */
const PROCESSOR_URL = new URL("./synth-processor.ts", import.meta.url);

/**
 * Create a SynthInstrument connected to the given AudioContext.
 * Must call `audioCtx.audioWorklet.addModule()` first via loadWorkletModule().
 */
export async function createSynthInstrument(
  ctx: AudioContext,
): Promise<SynthInstrument> {
  // Load the worklet module
  await ctx.audioWorklet.addModule(PROCESSOR_URL.href);

  const node = new AudioWorkletNode(ctx, "synth-processor", {
    numberOfInputs: 0,
    numberOfOutputs: 1,
    outputChannelCount: [2],
  });

  const params: SynthParameterMap = { ...DEFAULT_SYNTH_PARAMS };

  function postCommand(cmd: SynthVoiceCommand): void {
    node.port.postMessage(cmd);
  }

  const instrument: SynthInstrument = {
    output: node,
    params,

    noteOn(note: number, velocity: number, legato = false): void {
      postCommand({ type: "noteOn", note, velocity, legato });
    },

    noteOff(note: number): void {
      postCommand({ type: "noteOff", note });
    },

    allNotesOff(): void {
      postCommand({ type: "allNotesOff" });
    },

    setParam<K extends keyof SynthParameterMap>(
      key: K,
      value: SynthParameterMap[K],
    ): void {
      (params as Record<string, unknown>)[key] = value;

      // Map enum types to numeric index for the worklet
      let numericValue: number;
      if (typeof value === "string") {
        // Lookup string in appropriate type array
        switch (key) {
          case "osc1Type":
          case "osc2Type":
            numericValue = WAVEFORM_TYPES.indexOf(
              value as (typeof WAVEFORM_TYPES)[number],
            );
            break;
          case "filterType":
            numericValue = FILTER_TYPES.indexOf(
              value as (typeof FILTER_TYPES)[number],
            );
            break;
          case "lfo1Shape":
          case "lfo2Shape":
            numericValue = LFO_SHAPES.indexOf(
              value as (typeof LFO_SHAPES)[number],
            );
            break;
          default:
            numericValue = 0;
        }
      } else {
        numericValue = value;
      }

      postCommand({
        type: "setParam",
        key: key as string,
        value: numericValue,
      });
    },

    setModRoutes(routes: WorkletModRoute[]): void {
      postCommand({ type: "setModRoutes", routes });
    },

    setModSource(source: string, value: number): void {
      postCommand({ type: "setModSource", source, value });
    },

    connectToMixer(mixer: MixerEngine, trackId: string): void {
      const strip = mixer.getOrCreateStrip(trackId);
      node.connect(strip.inputGain);
    },

    disconnectFromMixer(_mixer: MixerEngine, _trackId: string): void {
      node.disconnect();
    },

    dispose(): void {
      node.disconnect();
      node.port.close();
    },
  };

  return instrument;
}

/**
 * Shared types for the synthesizer engine.
 * Used by both the AudioWorklet processor and main thread.
 *
 * Exports: SynthParameterMap, SynthVoiceCommand (as specified by epic).
 */

import type { WaveformType } from "./dsp/polyblep";
import type { FilterType } from "./dsp/biquad-coeffs";
import type { LFOShape } from "./dsp/lfo";

// ─── Voice Commands (main thread → worklet) ───

export type SynthVoiceCommand =
  | { type: "noteOn"; note: number; velocity: number; legato: boolean }
  | { type: "noteOff"; note: number }
  | { type: "allNotesOff" }
  | { type: "setParam"; key: string; value: number }
  | {
      type: "setModRoutes";
      routes: {
        sourceIdx: number;
        destIdx: number;
        amount: number;
        bipolar: boolean;
      }[];
    }
  | { type: "setModSource"; source: string; value: number };

// ─── Parameter Map ───

export type SynthParameterMap = {
  // Oscillator 1
  osc1Type: WaveformType;
  osc1Octave: number; // -2..+2
  osc1Detune: number; // cents, -100..+100
  osc1Level: number; // 0..1

  // Oscillator 2
  osc2Type: WaveformType;
  osc2Octave: number;
  osc2Detune: number;
  osc2Level: number;

  // Filter
  filterType: FilterType;
  filterCutoff: number; // Hz, 20..20000
  filterResonance: number; // Q, 0.5..20

  // Amplitude Envelope
  ampAttack: number; // seconds
  ampDecay: number;
  ampSustain: number; // 0..1
  ampRelease: number;

  // Filter Envelope
  filterAttack: number;
  filterDecay: number;
  filterSustain: number; // 0..1
  filterRelease: number;
  filterEnvDepth: number; // semitones, -60..+60

  // LFO 1
  lfo1Rate: number; // Hz, 0.1..20
  lfo1Depth: number; // 0..1
  lfo1Shape: LFOShape;

  // LFO 2
  lfo2Rate: number; // Hz, 0.1..20
  lfo2Depth: number; // 0..1
  lfo2Shape: LFOShape;

  // Glide
  glideTime: number; // seconds, 0..1

  // Master
  masterGain: number; // 0..1
};

/** Default parameter values */
export const DEFAULT_SYNTH_PARAMS: SynthParameterMap = {
  osc1Type: "saw",
  osc1Octave: 0,
  osc1Detune: 0,
  osc1Level: 0.8,

  osc2Type: "saw",
  osc2Octave: 0,
  osc2Detune: 7, // Slight detune for thickness
  osc2Level: 0.5,

  filterType: "lowpass",
  filterCutoff: 5000,
  filterResonance: 1,

  ampAttack: 0.01,
  ampDecay: 0.2,
  ampSustain: 0.7,
  ampRelease: 0.3,

  filterAttack: 0.01,
  filterDecay: 0.3,
  filterSustain: 0.3,
  filterRelease: 0.5,
  filterEnvDepth: 24,

  lfo1Rate: 5,
  lfo1Depth: 0,
  lfo1Shape: "sine",

  lfo2Rate: 3,
  lfo2Depth: 0,
  lfo2Shape: "sine",

  glideTime: 0,

  masterGain: 0.7,
};

// ─── MIDI → Frequency Conversion ───

/** Convert MIDI note number to frequency in Hz. A4 = 69 = 440Hz. */
export function midiToFreq(note: number): number {
  return 440 * Math.pow(2, (note - 69) / 12);
}

/** Waveform type index mapping for AudioParam/message passing */
export const WAVEFORM_TYPES: readonly WaveformType[] = [
  "sine",
  "saw",
  "square",
  "triangle",
];

/** Filter type index mapping */
export const FILTER_TYPES: readonly FilterType[] = [
  "lowpass",
  "highpass",
  "bandpass",
];

/** LFO shape index mapping */
export const LFO_SHAPES: readonly LFOShape[] = [
  "sine",
  "square",
  "triangle",
  "sample-and-hold",
];

