    expect(events[1]?.note).toBe(64);
    expect(events[2]?.note).toBe(60); // wraps
    expect(events[3]?.note).toBe(64);
  });

  // ─── setParams ───

  it("setParams updates arpeggiator behavior", () => {
    const arp = makeArp({ pattern: "up" });
    arp.noteOn(60, 100);
    arp.noteOn(64, 100);

