    const arp = makeArp({ pattern: "up" });
    arp.noteOn(60, 100);
    arp.noteOn(64, 100);

    arp.scheduleStep(0, 0.0, 0.25);
    arp.scheduleStep(1, 0.25, 0.25);

    arp.reset();
    events.length = 0;

    arp.scheduleStep(0, 0.5, 0.25);
    expect(events[0]?.note).toBe(60); // restarted from beginning
  });
});

