          ...s.arps,
          [trackId]: {
            ...arp,
            params: { ...arp.params, [key]: value },
          },
        },
      };
    });
  },

  setParams(trackId, params) {
    set((s) => {
      const arp = s.arps[trackId];
      if (!arp) return s;
      return {
        arps: {
          ...s.arps,
          [trackId]: { ...arp, params },
        },
      };
    });
  },

  getParams(trackId) {
    const arp = get().arps[trackId];
    return arp?.params ?? { ...DEFAULT_ARP_PARAMS };
  },
}));

