1	/**
2	 * Arpeggiator engine: generates note events from held MIDI notes.
3	 * Pure logic - no audio thread code. Driven by external scheduler via scheduleStep().
4	 *
5	 * Patterns: up, down, up-down, down-up, random, as-played.
6	 * Octave expansion with direction control. Gate, swing, latch mode.
7	 *
8	 * EARS: R-EVT-15, R-STA-07 (latch)
9	 */
10	
11	import type { ArpNoteEvent, ArpParams } from "./arpeggiator-types";
12	
13	export type Arpeggiator = {
14	  /** Add a held note */
15	  noteOn(note: number, velocity: number): void;
16	  /** Release a held note */
17	  noteOff(note: number): void;
18	  /** Release all held notes */
19	  allNotesOff(): void;
20	  /** Schedule one arpeggiator step at the given time */
21	  scheduleStep(stepIndex: number, time: number, stepDuration: number): void;
22	  /** Get currently held notes (sorted ascending for "up" etc.) */
23	  getHeldNotes(): readonly number[];
24	  /** Update parameters */
25	  setParams(params: ArpParams): void;
26	  /** Reset step counter and internal state */
27	  reset(): void;
28	};
29	
30	type HeldNote = {
31	  note: number;
32	  velocity: number;
33	  order: number; // insertion order for "as-played"
34	};
35	
36	export function createArpeggiator(
37	  onNote: (event: ArpNoteEvent) => void,
38	  initialParams: ArpParams,
39	): Arpeggiator {
40	  let params = { ...initialParams };
41	  let heldNotes: HeldNote[] = [];
42	  let latchedNotes: HeldNote[] = [];
43	  let isLatched = false; // true when all keys released while latch is on
44	  let insertionCounter = 0;
45	  let stepCounter = 0; // internal step for pattern position tracking
46	
47	  /** Get the active note pool (held or latched) */
48	  function getPool(): HeldNote[] {
49	    if (params.latch && isLatched && latchedNotes.length > 0) {
50	      return latchedNotes;
51	    }
52	    return heldNotes;
53	  }
54	
55	  /** Build the expanded note sequence for current pool + octave settings */
56	  function buildSequence(): { note: number; velocity: number }[] {
57	    const pool = getPool();
58	    if (pool.length === 0) return [];
59	
60	    // Sort by pattern
61	    let sorted: HeldNote[];
62	    if (params.pattern === "as-played") {
63	      sorted = [...pool].sort((a, b) => a.order - b.order);
64	    } else {
65	      sorted = [...pool].sort((a, b) => a.note - b.note);
66	    }
67	
68	    // Build octave-expanded sequence
69	    const octaves = buildOctaveSequence(params.octaveRange, params.octaveDirection);
70	    const expanded: { note: number; velocity: number }[] = [];
71	
72	    for (const octOffset of octaves) {
73	      for (const h of sorted) {
74	        const n = h.note + octOffset * 12;
75	        if (n >= 0 && n <= 127) {
76	          expanded.push({ note: n, velocity: h.velocity });
77	        }
78	      }
79	    }
80	
81	    return expanded;
82	  }
83	
84	  /** Get the note at the given pattern index from the sequence */
85	  function getNoteAtStep(seq: { note: number; velocity: number }[], step: number): { note: number; velocity: number } | undefined {
86	    if (seq.length === 0) return undefined;
87	
88	    switch (params.pattern) {
89	      case "up":
90	      case "as-played":
91	        return seq[step % seq.length];
92	
93	      case "down": {
94	        const reversed = [...seq].reverse();
95	        return reversed[step % reversed.length];
96	      }
97	
98	      case "up-down": {
99	        if (seq.length <= 1) return seq[0];
100	        // Build bounce: [0, 1, ..., n-1, n-2, ..., 1]
101	        const bounce = buildBounceSequence(seq.length);
102	        return seq[bounce[step % bounce.length]!];
103	      }
104	
105	      case "down-up": {
106	        if (seq.length <= 1) return seq[0];
107	        // Build reverse bounce: [n-1, n-2, ..., 0, 1, ..., n-2]
108	        const bounce = buildBounceSequence(seq.length);
109	        const reversed = bounce.map((i) => seq.length - 1 - i);
110	        return seq[reversed[step % reversed.length]!];
111	      }
112	
113	      case "random":
114	        return seq[Math.floor(Math.random() * seq.length)];
115	
116	      default:
117	        return seq[step % seq.length];
118	    }
119	  }
120	
121	  const arp: Arpeggiator = {
122	    noteOn(note: number, velocity: number): void {
123	      // If latched and new note arrives, clear latch pool
124	      if (params.latch && isLatched && heldNotes.length === 0) {
125	        latchedNotes = [];
126	        isLatched = false;
127	        stepCounter = 0;
128	      }
129	
130	      // Don't add duplicates
131	      if (heldNotes.some((h) => h.note === note)) return;
132	
133	      heldNotes.push({ note, velocity, order: insertionCounter++ });
134	    },
135	
136	    noteOff(note: number): void {
137	      const idx = heldNotes.findIndex((h) => h.note === note);
138	      if (idx === -1) return;
139	
140	      heldNotes.splice(idx, 1);
141	
142	      // If latch is on and all keys released, freeze the pool
143	      if (params.latch && heldNotes.length === 0) {
144	        if (!isLatched) {
145	          // First time all released - latch current pool
146	          latchedNotes = [...getPoolBeforeRelease(note)];
147	          isLatched = true;
148	        }
149	      }
150	    },
151	
152	    allNotesOff(): void {
153	      heldNotes = [];
154	      latchedNotes = [];
155	      isLatched = false;
156	      stepCounter = 0;
157	    },
158	
159	    scheduleStep(stepIndex: number, time: number, stepDuration: number): void {
160	      const seq = buildSequence();
161	      if (seq.length === 0) return;
162	
163	      const entry = getNoteAtStep(seq, stepCounter);
164	      if (!entry) return;
165	
166	      // Apply swing: shift odd steps forward
167	      let adjustedTime = time;
168	      if (params.swing > 0 && stepIndex % 2 === 1) {
169	        adjustedTime += (params.swing * stepDuration) / 3;
170	      }
171	
172	      const duration = stepDuration * params.gate;
173	
174	      onNote({
175	        note: entry.note,
176	        velocity: entry.velocity,
177	        startTime: adjustedTime,
178	        duration,
179	      });
180	
181	      stepCounter++;
182	    },
183	
184	    getHeldNotes(): readonly number[] {
185	      return heldNotes.map((h) => h.note);
186	    },
187	
188	    setParams(newParams: ArpParams): void {
189	      const patternChanged = newParams.pattern !== params.pattern;
190	      params = { ...newParams };
191	      if (patternChanged) {
192	        stepCounter = 0;
193	      }
194	    },
195	
196	    reset(): void {
197	      stepCounter = 0;
198	      latchedNotes = [];
199	      isLatched = false;
200	    },
201	  };
202	
203	  // Helper: get pool including the note about to be released (for latch)
204	  function getPoolBeforeRelease(releasedNote: number): HeldNote[] {
205	    // The note was already removed from heldNotes, reconstruct
206	    const existing = [...heldNotes];
207	    // Find it in the last known latch or reconstruct from the pattern
208	    // Since heldNotes is already empty at this point, use latchedNotes if available
209	    if (latchedNotes.length > 0) return latchedNotes;
210	    // This note was the last one - reconstruct from the previous step's pool
211	    // Actually we need to capture before the last noteOff
212	    return [{ note: releasedNote, velocity: 100, order: 0 }, ...existing];
213	  }
214	
215	  return arp;
216	}
217	
218	/** Build the octave offset sequence for the given range and direction */
219	function buildOctaveSequence(range: number, direction: "up" | "down" | "up-down"): number[] {
220	  if (range <= 1) return [0];
221	
222	  switch (direction) {
223	    case "up": {
224	      const offsets: number[] = [];
225	      for (let i = 0; i < range; i++) offsets.push(i);
226	      return offsets;
227	    }
228	    case "down": {
229	      const offsets: number[] = [];
230	      for (let i = range - 1; i >= 0; i--) offsets.push(-i);
231	      // Reverse so lowest octave is last
232	      return offsets;
233	    }
234	    case "up-down": {
235	      // 0, 1, ..., range-1, range-2, ..., 1 (skip endpoints in bounce)
236	      const up: number[] = [];
237	      for (let i = 0; i < range; i++) up.push(i);
238	      const down: number[] = [];
239	      for (let i = range - 2; i > 0; i--) down.push(i);
240	      return [...up, ...down];
241	    }
242	  }
243	}
244	
245	/** Build bounce indices: [0, 1, ..., n-1, n-2, ..., 1] */
246	function buildBounceSequence(length: number): number[] {
247	  if (length <= 1) return [0];
248	  const indices: number[] = [];
249	  for (let i = 0; i < length; i++) indices.push(i);
250	  for (let i = length - 2; i > 0; i--) indices.push(i);
251	  return indices;
252	}
253

1	/**
2	 * Zustand store for per-track arpeggiator state.
3	 * Follows synth-store.ts pattern: keyed by track ID.
4	 */
5	
6	import { create } from "zustand";
7	import type { ArpParams } from "@audio/arpeggiator/arpeggiator-types";
8	import { DEFAULT_ARP_PARAMS } from "@audio/arpeggiator/arpeggiator-types";
9	
10	export type ArpTrackState = {
11	  readonly trackId: string;
12	  readonly params: ArpParams;
13	};
14	
15	export type ArpeggiatorStore = {
16	  /** Per-track arpeggiator state keyed by track ID */
17	  arps: Record<string, ArpTrackState>;
18	
19	  /** Initialize arpeggiator state for a track */
20	  initArp: (trackId: string) => void;
21	  /** Remove arpeggiator state for a track */
22	  removeArp: (trackId: string) => void;
23	  /** Set a single arpeggiator parameter for a track */
24	  setParam: <K extends keyof ArpParams>(
25	    trackId: string,
26	    key: K,
27	    value: ArpParams[K],
28	  ) => void;
29	  /** Set all arpeggiator parameters for a track */
30	  setParams: (trackId: string, params: ArpParams) => void;
31	  /** Get arp params for a track (returns defaults if not initialized) */
32	  getParams: (trackId: string) => ArpParams;
33	};
34	
35	export const useArpeggiatorStore = create<ArpeggiatorStore>()((set, get) => ({
36	  arps: {},
37	
38	  initArp(trackId) {
39	    set((s) => {
40	      if (s.arps[trackId]) return s;
41	      return {
42	        arps: {
43	          ...s.arps,
44	          [trackId]: {
45	            trackId,
46	            params: { ...DEFAULT_ARP_PARAMS },
47	          },
48	        },
49	      };
50	    });
51	  },
52	
53	  removeArp(trackId) {
54	    set((s) => {
55	      if (!s.arps[trackId]) return s;
56	      return {
57	        arps: Object.fromEntries(
58	          Object.entries(s.arps).filter(([k]) => k !== trackId),
59	        ),
60	      };
61	    });
62	  },
63	
64	  setParam(trackId, key, value) {
65	    set((s) => {
66	      const arp = s.arps[trackId];
67	      if (!arp) return s;
68	      return {
69	        arps: {
70	          ...s.arps,
71	          [trackId]: {
72	            ...arp,
73	            params: { ...arp.params, [key]: value },
74	          },
75	        },
76	      };
77	    });
78	  },
79	
80	  setParams(trackId, params) {
81	    set((s) => {
82	      const arp = s.arps[trackId];
83	      if (!arp) return s;
84	      return {
85	        arps: {
86	          ...s.arps,
87	          [trackId]: { ...arp, params },
88	        },
89	      };
90	    });
91	  },
92	
93	  getParams(trackId) {
94	    const arp = get().arps[trackId];
95	    return arp?.params ?? { ...DEFAULT_ARP_PARAMS };
96	  },
97	}));
98

