6	describe("createArpeggiator", () => {
7	  let events: ArpNoteEvent[];
8	  let onNote: (e: ArpNoteEvent) => void;
9	
10	  beforeEach(() => {
11	    events = [];
12	    onNote = (e): void => {
13	      events.push(e);
14	    };
15	  });
16	
17	  function makeArp(overrides?: Partial<ArpParams>) {
18	    return createArpeggiator(onNote, {
19	      ...DEFAULT_ARP_PARAMS,
20	      enabled: true,
21	      ...overrides,
22	    });
23	  }
24	
25	  // ─── Basic note management ───
26	
27	  it("creates an arpeggiator with empty held notes", () => {
28	    const arp = makeArp();
29	    expect(arp.getHeldNotes()).toEqual([]);
30	  });
31	
32	  it("noteOn adds to held notes", () => {
33	    const arp = makeArp();
34	    arp.noteOn(60, 100);
35	    expect(arp.getHeldNotes()).toEqual([60]);
36	  });
37	
38	  it("noteOff removes from held notes", () => {
39	    const arp = makeArp();
40	    arp.noteOn(60, 100);
41	    arp.noteOn(64, 90);
42	    arp.noteOff(60);
43	    expect(arp.getHeldNotes()).toEqual([64]);
44	  });
45	
46	  it("duplicate noteOn does not add twice", () => {
47	    const arp = makeArp();
48	    arp.noteOn(60, 100);
49	    arp.noteOn(60, 80);
50	    expect(arp.getHeldNotes()).toEqual([60]);
51	  });
52	
53	  it("allNotesOff clears held notes", () => {
54	    const arp = makeArp();
55	    arp.noteOn(60, 100);
56	    arp.noteOn(64, 90);
57	    arp.allNotesOff();
58	    expect(arp.getHeldNotes()).toEqual([]);
59	  });
60	
61	  // ─── Pattern: up ───
62	
63	  it("pattern up: plays notes in ascending order", () => {
64	    const arp = makeArp({ pattern: "up" });
65	    arp.noteOn(64, 100); // E4
66	    arp.noteOn(60, 100); // C4
67	    arp.noteOn(67, 100); // G4
68	
69	    // Schedule 3 steps at bpm=120, 1/8 notes = 0.25s per step
70	    arp.scheduleStep(0, 0.0, 0.25);
71	    arp.scheduleStep(1, 0.25, 0.25);
72	    arp.scheduleStep(2, 0.5, 0.25);
73	
74	    expect(events).toHaveLength(3);
75	    expect(events[0]?.note).toBe(60); // C4 (lowest)
76	    expect(events[1]?.note).toBe(64); // E4
77	    expect(events[2]?.note).toBe(67); // G4
