218	/** Build the octave offset sequence for the given range and direction */
219	function buildOctaveSequence(range: number, direction: "up" | "down" | "up-down"): number[] {
220	  if (range <= 1) return [0];
221	
222	  switch (direction) {
223	    case "up": {
224	      const offsets: number[] = [];
225	      for (let i = 0; i < range; i++) offsets.push(i);
226	      return offsets;
227	    }
228	    case "down": {
229	      const offsets: number[] = [];
230	      for (let i = range - 1; i >= 0; i--) offsets.push(-i);
231	      // Reverse so lowest octave is last
232	      return offsets;
233	    }
234	    case "up-down": {
235	      // 0, 1, ..., range-1, range-2, ..., 1 (skip endpoints in bounce)
236	      const up: number[] = [];
237	      for (let i = 0; i < range; i++) up.push(i);
238	      const down: number[] = [];
239	      for (let i = range - 2; i > 0; i--) down.push(i);
240	      return [...up, ...down];
241	    }
242	  }
243	}
244	
245	/** Build bounce indices: [0, 1, ..., n-1, n-2, ..., 1] */
246	function buildBounceSequence(length: number): number[] {
247	  if (length <= 1) return [0];
248	  const indices: number[] = [];
249	  for (let i = 0; i < length; i++) indices.push(i);
250	  for (let i = length - 2; i > 0; i--) indices.push(i);
251	  return indices;
252	}

121	  const arp: Arpeggiator = {
122	    noteOn(note: number, velocity: number): void {
123	      // If latched and new note arrives, clear latch pool
124	      if (params.latch && isLatched && heldNotes.length === 0) {
125	        latchedNotes = [];
126	        isLatched = false;
127	        stepCounter = 0;
128	      }
129	
130	      // Don't add duplicates
131	      if (heldNotes.some((h) => h.note === note)) return;
132	
133	      heldNotes.push({ note, velocity, order: insertionCounter++ });
134	    },
135	
136	    noteOff(note: number): void {
137	      const idx = heldNotes.findIndex((h) => h.note === note);
138	      if (idx === -1) return;
139	
140	      heldNotes.splice(idx, 1);
141	
142	      // If latch is on and all keys released, freeze the pool
143	      if (params.latch && heldNotes.length === 0) {
144	        if (!isLatched) {
145	          // First time all released - latch current pool
146	          latchedNotes = [...getPoolBeforeRelease(note)];
147	          isLatched = true;
148	        }
